This is a complete, single-file HTML solution. It uses **Three.js** (a standard 3D library) to render a house.

I have designed this to be **self-contained**. You do not need to download any external 3D models (like .obj or .gltf files). Instead, I have written code to **procedurally generate** a house using basic geometric shapes (cubes and pyramids).

### How to use this:
1.  Copy the code below.
2.  Save it as an `.html` file (e.g., `house.html`).
3.  Open that file in any modern web browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>3D House Render</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click & Drag to Rotate | Scroll to Zoom</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // --- 1. SCENE SETUP ---
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        document.body.appendChild(renderer.domElement);

        // --- 2. CONTROLS ---
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.target.set(0, 2, 0);

        // --- 3. LIGHTING ---
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1.5);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // --- 4. MATERIALS ---
        const materials = {
            wall: new THREE.MeshStandardMaterial({ color: 0xeeeeee, roughness: 0.8 }),
            roof: new THREE.MeshStandardMaterial({ color: 0x8B4513, roughness: 0.9 }),
            window: new THREE.MeshStandardMaterial({ color: 0x87CEEB, roughness: 0.1, metalness: 0.1 }),
            door: new THREE.MeshStandardMaterial({ color: 0x5c3a21, roughness: 0.8 }),
            grass: new THREE.MeshStandardMaterial({ color: 0x4caf50, roughness: 1.0 })
        };

        // --- 5. BUILDING THE HOUSE ---
        const houseGroup = new THREE.Group();

        // A. Ground
        const groundGeo = new THREE.PlaneGeometry(100, 100);
        const ground = new THREE.Mesh(groundGeo, materials.grass);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // B. Main Body (Cube)
        const bodyGeo = new THREE.BoxGeometry(8, 6, 8);
        const body = new THREE.Mesh(bodyGeo, materials.wall);
        body.position.y = 3; // Sit on top of ground
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // C. Roof (Pyramid)
        const roofGeo = new THREE.ConeGeometry(7, 4, 4); // 4 segments for pyramid
        const roof = new THREE.Mesh(roofGeo, materials.roof);
        roof.position.y = 8; // Sit on top of body
        roof.rotation.y = Math.PI / 4; // Rotate to align with cube
        roof.castShadow = true;
        houseGroup.add(roof);

        // D. Windows (Helper function)
        function createWindow(x, y, z, w, h) {
            const winGeo = new THREE.BoxGeometry(w, h, 0.2);
            const win = new THREE.Mesh(winGeo, materials.window);
            win.position.set(x, y, z);
            win.castShadow = true;
            houseGroup.add(win);
        }

        // Add Windows
        createWindow(2.5, 4, 3.9, 2, 2); // Front Left
        createWindow(-2.5, 4, 3.9, 2, 2); // Front Right
        createWindow(2.5, 4, -3.9, 2, 2); // Back Left
        createWindow(-2.5, 4, -3.9, 2, 2); // Back Right

        // E. Door
        const doorGeo = new THREE.BoxGeometry(2, 3.5, 0.2);
        const door = new THREE.Mesh(doorGeo, materials.door);
        door.position.set(0, 1.75, 4.1);
        door.castShadow = true;
        houseGroup.add(door);

        // F. Chimney
        const chimneyGeo = new THREE.BoxGeometry(1, 3, 1);
        const chimney = new THREE.Mesh(chimneyGeo, materials.wall);
        chimney.position.set(3, 9, 0);
        chimney.castShadow = true;
        houseGroup.add(chimney);

        // G. Tree (Simple Cone)
        const treeGeo = new THREE.ConeGeometry(2, 6, 8);
        const treeMat = new THREE.MeshStandardMaterial({ color: 0x228B22 });
        const tree = new THREE.Mesh(treeGeo, treeMat);
        tree.position.set(-8, 3, -8);
        tree.castShadow = true;
        scene.add(tree);

        // Add House to Scene
        scene.add(houseGroup);

        // --- 6. ANIMATION LOOP ---
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Window Resize
        window.addEventListener('resize', onWindowResize, false);
        function onWindowResize() {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        }

        animate();
    </script>
</body>
</html>
```

### Key Features of this Code:
1.  **Procedural Generation:** The house is built using `THREE.BoxGeometry` (for walls/doors) and `THREE.ConeGeometry` (for the roof). This ensures the code works instantly without needing external assets.
2.  **Lighting & Shadows:** It uses a `DirectionalLight` to simulate the sun, casting realistic shadows on the ground and the house itself.
3.  **Interactivity:** I included `OrbitControls`. You can click and drag to rotate around the house, or scroll to zoom in and out.
4.  **Responsive:** The canvas automatically resizes if you change the browser window size.
